// pubspec: get: ^4.6.6
import 'package:flutter/material.dart';
import 'package:get/get.dart';

// 1. Controller — plain class holding .obs state
class CounterController extends GetxController {
  final count = 0.obs;                // RxInt — reactive observable

  void increment() => count.value++;   // triggers Obx rebuild
  void reset() => count.value = 0;
}

// 2. Root — use GetMaterialApp instead of MaterialApp for routing/snackbar hooks
void main() => runApp(GetMaterialApp(home: HomePage()));

class HomePage extends StatelessWidget {
  const HomePage({super.key});

  @override
  Widget build(BuildContext context) {
    final c = Get.put(CounterController());   // create + register in global DI

    return Scaffold(
      appBar: AppBar(title: const Text('GetX demo')),
      body: Center(
        // Obx auto-rebuilds when any .obs read inside it changes.
        child: Obx(() => Text('${c.count.value}', style: const TextStyle(fontSize: 40))),
      ),
      floatingActionButton: Column(
        mainAxisAlignment: MainAxisAlignment.end,
        children: [
          FloatingActionButton(
            heroTag: 'inc',
            onPressed: c.increment,
            child: const Icon(Icons.add),
          ),
          const SizedBox(height: 8),
          FloatingActionButton(
            heroTag: 'nav',
            onPressed: () => Get.to(() => const DetailPage()),
            child: const Icon(Icons.arrow_forward),
          ),
        ],
      ),
    );
  }
}

class DetailPage extends StatelessWidget {
  const DetailPage({super.key});

  @override
  Widget build(BuildContext context) {
    // Access the SAME controller from anywhere — no BuildContext, no ref
    final c = Get.find<CounterController>();
    return Scaffold(
      appBar: AppBar(title: const Text('Detail')),
      body: Center(
        child: Column(mainAxisAlignment: MainAxisAlignment.center, children: [
          Obx(() => Text('shared count: ${c.count.value}',
            style: const TextStyle(fontSize: 24))),
          FilledButton(
            onPressed: () {
              c.reset();
              Get.snackbar('Reset', 'Count is back to 0');
            },
            child: const Text('Reset + show snackbar'),
          ),
        ]),
      ),
    );
  }
}
